def get_config_dir():
    """Get the configuration directory path based on the OS."""
    home = Path.home()
    config_dir = home / CONFIG_DIR_NAME
    return config_dir


def create_config_directories():
    """Create necessary configuration directories for the package."""
    config_dir = get_config_dir()
    subdirs = ["config", "logs", "cache", "resources", "templates", "data"]

    print(f"[Setup] Creating configuration directories under: {config_dir}")

    for subdir in subdirs:
        dir_path = config_dir / subdir
        dir_path.mkdir(parents=True, exist_ok=True)
        print(f"  [Created] {dir_path}")

    # Create a default configuration file if it doesn't exist
    default_config_path = config_dir / "config" / "settings.json"
    if not default_config_path.exists():
        default_config = {
            "version": PACKAGE_VERSION,
            "log_level": "INFO",
            "log_dir": str(config_dir / "logs"),
            "cache_dir": str(config_dir / "cache"),
            "resource_dir": str(config_dir / "resources"),
            "template_dir": str(config_dir / "templates"),
            "data_dir": str(config_dir / "data"),
            "api_endpoint": "https://internal-api.company.com/v1",
            "timeout": 30,
            "retry_count": 3,
            "features": {
                "auto_update": True,
                "telemetry": False,
                "debug_mode": False,
            },
        }
        with open(default_config_path, "w") as f:
            json.dump(default_config, f, indent=4)
        print(f"  [Created] Default config: {default_config_path}")

    return config_dir


def download_resources(config_dir):
    """Download additional resources needed by the package."""
    resource_dir = config_dir / "resources"
    resource_dir.mkdir(parents=True, exist_ok=True)

    print("[Setup] Downloading additional resources...")

    for filename, url in RESOURCE_URLS.items():
        dest_path = resource_dir / filename
        if dest_path.exists():
            print(f"  [Skipped] {filename} already exists at {dest_path}")
            continue

        try:
            print(f"  [Downloading] {filename} from {url}...")
            urllib.request.urlretrieve(url, str(dest_path))
            print(f"  [Downloaded] {filename} -> {dest_path}")
        except Exception as e:
            print(f"  [Warning] Could not download {filename}: {e}")
            # Create a placeholder file so installation doesn't fail
            if filename.endswith(".json"):
                with open(dest_path, "w") as f:
                    json.dump({"placeholder": True, "source": url}, f, indent=4)
                print(f"  [Created] Placeholder for {filename}")

    # Create a resource manifest
    manifest_path = resource_dir / "manifest.json"
    manifest = {
        "package": PACKAGE_NAME,
        "version": PACKAGE_VERSION,
        "resources": {
            name: {
                "url": url,
                "local_path": str(resource_dir / name),
                "downloaded": (resource_dir / name).exists(),
            }
            for name, url in RESOURCE_URLS.items()
        },
    }
    with open(manifest_path, "w") as f:
        json.dump(manifest, f, indent=4)
    print(f"  [Created] Resource manifest: {manifest_path}")


def setup_environment_variables(config_dir):
    """Set up environment variables for the package."""
    print("[Setup] Configuring environment variables...")

    env_vars = ENV_VARS.copy()
    env_vars["INTERNAL_TOOLKIT_HOME"] = str(config_dir)
    env_vars["INTERNAL_TOOLKIT_CONFIG"] = str(config_dir / "config" / "settings.json")

    # Write environment variables to a shell-sourceable file
    env_file_bash = config_dir / "env.sh"
    env_file_fish = config_dir / "env.fish"
    env_file_bat = config_dir / "env.bat"
    env_file_json = config_dir / "env.json"

    # Bash/Zsh compatible
    with open(env_file_bash, "w") as f:
        f.write("#!/bin/bash\n")
        f.write(f"# Environment variables for {PACKAGE_NAME} v{PACKAGE_VERSION}\n")
        f.write("# Source this file: source ~/.internal_toolkit/env.sh\n\n")
        for key, value in env_vars.items():
            f.write(f'export {key}="{value}"\n')
    print(f"  [Created] Bash env file: {env_file_bash}")

    # Fish shell compatible
    with open(env_file_fish, "w") as f:
        f.write(f"# Environment variables for {PACKAGE_NAME} v{PACKAGE_VERSION}\n")
        f.write("# Source this file: source ~/.internal_toolkit/env.fish\n\n")
        for key, value in env_vars.items():
            f.write(f'set -gx {key} "{value}"\n')
    print(f"  [Created] Fish env file: {env_file_fish}")

    # Windows batch file
    with open(env_file_bat, "w") as f:
        f.write(f"@echo off\n")
        f.write(f"REM Environment variables for {PACKAGE_NAME} v{PACKAGE_VERSION}\n\n")
        for key, value in env_vars.items():
            f.write(f'set {key}={value}\n')
    print(f"  [Created] Windows env file: {env_file_bat}")

    # JSON format for programmatic access
    with open(env_file_json, "w") as f:
        json.dump(env_vars, f, indent=4)
    print(f"  [Created] JSON env file: {env_file_json}")

    # Set environment variables for the current process
    for key, value in env_vars.items():
        os.environ[key] = value
        print(f"  [Set] {key}={value}")

    # Try to add to shell profile if on Unix-like systems
    if sys.platform != "win32":
        _append_to_shell_profile(env_file_bash)
    else:
        _set_windows_env_vars(env_vars)

    return env_vars


def _append_to_shell_profile(env_file_path):
    """Append source command to shell profile files."""
    home = Path.home()
    source_line = f'\n# {PACKAGE_NAME} environment\nif [ -f "{env_file_path}" ]; then source "{env_file_path}"; fi\n'

    profiles = [
        home / ".bashrc",
        home / ".zshrc",
        home / ".profile",
    ]

    for profile in profiles:
        if profile.exists():
            content = profile.read_text()
            if str(env_file_path) not in content:
                try:
                    with open(profile, "a") as f:
                        f.write(source_line)
                    print(f"  [Updated] Added source line to {profile}")
                except PermissionError:
                    print(f"  [Warning] Could not update {profile} (permission denied)")


def _set_windows_env_vars(env_vars):
    """Set persistent environment variables on Windows."""
    try:
        import winreg

        key = winreg.OpenKey(
            winreg.HKEY_CURRENT_USER, "Environment", 0, winreg.KEY_SET_VALUE
        )
        for name, value in env_vars.items():
            winreg.SetValueEx(key, name, 0, winreg.REG_SZ, value)
            print(f"  [Registry] Set {name} in Windows registry")
        winreg.CloseKey(key)
    except Exception as e:
        print(f"  [Warning] Could not set Windows registry variables: {e}")


def run_post_install_tasks():
    """Run all post-installation tasks."""
